//! Golden tests for the exporters.
//!
//! These replay fixtures generated by the reference JS in
//! `goldens/gen/export_ref.mjs` (a DOM-/Intl-free reimplementation of the EXACT
//! `index.html` export/copy formatting) and assert the Rust port produces
//! byte-identical Markdown / transcript text / executive lines.
//!
//! Regenerate goldens: `node crates/silent-core/goldens/gen/export_ref.mjs`.
#![allow(
    clippy::unwrap_used,
    clippy::expect_used,
    reason = "tests use unwrap/expect as the assertion mechanism (PRD lint config)"
)]

use serde::Deserialize;
use silent_core::export::{
    AiNoteGroup, NoteCategory, NoteRecord, TranscriptLine, executive_line, history_replay_markdown,
    notes_to_markdown, summary_markdown_with_ai, transcript_text,
};
use std::path::PathBuf;

fn goldens_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("goldens/export")
}

fn load<T: for<'de> Deserialize<'de>>(name: &str) -> T {
    let path = goldens_dir().join(name);
    let bytes =
        std::fs::read(&path).unwrap_or_else(|e| panic!("read golden {}: {e}", path.display()));
    serde_json::from_slice(&bytes)
        .unwrap_or_else(|e| panic!("parse golden {}: {e}", path.display()))
}

// The JS fixtures use camelCase note records with string categories; the silent
// -core `NoteRecord` uses snake_case category strings (which match the JS values
// `decisions`/`actions`/`keypoints`/`questions`) so serde deserializes the
// fixture note arrays directly into `Vec<NoteRecord>`.

#[derive(Deserialize)]
struct NotesFixture {
    input: NotesInput,
    expected: String,
}
#[derive(Deserialize)]
struct NotesInput {
    title: String,
    date: String,
    duration: String,
    #[serde(rename = "withTime")]
    with_time: bool,
    notes: Vec<NoteRecord>,
}

fn check_notes_to_markdown(name: &str) {
    let f: NotesFixture = load(name);
    let got = notes_to_markdown(
        &f.input.title,
        &f.input.date,
        &f.input.duration,
        &f.input.notes,
        f.input.with_time,
    );
    assert_eq!(got, f.expected, "{name}: notes_to_markdown mismatch");
}

#[test]
fn notes_with_time() {
    check_notes_to_markdown("notes_with_time.json");
}
#[test]
fn notes_no_time() {
    check_notes_to_markdown("notes_no_time.json");
}
#[test]
fn notes_empty_title() {
    check_notes_to_markdown("notes_empty_title.json");
}

