#[derive(Deserialize)]
struct SummaryFixture {
    input: SummaryInput,
    expected: String,
}
#[derive(Deserialize)]
struct SummaryInput {
    title: String,
    date: String,
    duration: String,
    #[serde(rename = "withTime")]
    with_time: bool,
    notes: Vec<NoteRecord>,
    #[serde(rename = "aiGroups")]
    ai_groups: Vec<AiNoteGroup>,
}

#[test]
fn summary_with_ai_notes() {
    let f: SummaryFixture = load("summary_with_ai_notes.json");
    // The JS builds the base notes markdown first, then appends AI groups; the
    // Rust port composes the same two pure functions.
    let base = notes_to_markdown(
        &f.input.title,
        &f.input.date,
        &f.input.duration,
        &f.input.notes,
        f.input.with_time,
    );
    let got = summary_markdown_with_ai(&base, &f.input.ai_groups);
    assert_eq!(got, f.expected, "summary_with_ai_notes mismatch");
}

// Sanity: the fixture category strings round-trip to the enum we expect.
#[test]
fn fixture_categories_deserialize() {
    let f: NotesFixture = load("notes_with_time.json");
    assert!(
        f.input
            .notes
            .iter()
            .any(|n| n.category == NoteCategory::Questions),
        "fixture should contain a questions note"
    );
}
